"""
An implementation of `urlparse` that provides URL validation and normalization
as described by RFC3986.

We rely on this implementation rather than the one in Python's stdlib, because:

* It provides more complete URL validation.
* It properly differentiates between an empty querystring and an absent querystring,
  to distinguish URLs with a trailing '?'.
* It handles scheme, hostname, port, and path normalization.
* It supports IDNA hostnames, normalizing them to their encoded form.
* The API supports passing individual components, as well as the complete URL string.

Previously we relied on the excellent `rfc3986` package to handle URL parsing and
validation, but this module provides a simpler alternative, with less indirection
required.
"""
import ipaddress
import re
import typing

import idna

from ._exceptions import InvalidURL

MAX_URL_LENGTH = 65536

# https://datatracker.ietf.org/doc/html/rfc3986.html#section-2.3
UNRESERVED_CHARACTERS = (
    "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789-._~"
)
SUB_DELIMS = "!$&'()*+,;="

PERCENT_ENCODED_REGEX = re.compile("%[A-Fa-f0-9]{2}")


# {scheme}:      (optional)
# //{authority}  (optional)
# {path}
# ?{query}       (optional)
# #{fragment}    (optional)
URL_REGEX = re.compile(
    (
        r"(?:(?P<scheme>{scheme}):)?"
        r"(?://(?P<authority>{authority}))?"
        r"(?P<path>{path})"
        r"(?:\?(?P<query>{query}))?"
        r"(?:#(?P<fragment>{fragment}))?"
    ).format(
        scheme="([a-zA-Z][a-zA-Z0-9+.-]*)?",
        authority="[^/?#]*",
        path="[^?#]*",
        query="[^#]*",
        fragment=".*",
    )
)

# {userinfo}@    (optional)
# {host}
# :{port}        (optional)
AUTHORITY_REGEX = re.compile(
    (
        r"(?:(?P<userinfo>{userinfo})@)?" r"(?P<host>{host})" r":?(?P<port>{port})?"
    ).format(
        userinfo=".*",  # Any character sequence.
        host="(\\[.*\\]|[^:@]*)",  # Either any character sequence excluding ':' or '@',
        # or an IPv6 address enclosed within square brackets.
        port=".*",  # Any character sequence.
    )
)


# If we call urlparse with an individual component, then we need to regex
# validate that component individually.
# Note that we're duplicating the same strings as above. Shock! Horror!!
COMPONENT_REGEX = {
    "scheme": re.compile("([a-zA-Z][a-zA-Z0-9+.-]*)?"),
    "authority": re.compile("[^/?#]*"),
    "path": re.compile("[^?#]*"),
    "query": re.compile("[^#]*"),
    "fragment": re.compile(".*"),
    "userinfo": re.compile("[^@]*"),
    "host": re.compile("(\\[.*\\]|[^:]*)"),
    "port": re.compile(".*"),
}


# We use these simple regexs as a first pass before handing off to
# the stdlib 'ipaddress' module for IP address validation.
IPv4_STYLE_HOSTNAME = re.compile(r"^[0-9]+\.[0-9]+\.[0-9]+\.[0-9]+$")
IPv6_STYLE_HOSTNAME = re.compile(r"^\[.*\]$")


class ParseResult(typing.NamedTuple):
    scheme: str
    userinfo: str
    host: str
    port: typing.Optional[int]
    path: str
    query: typing.Optional[str]
    fragment: typing.Optional[str]

    @property
    def authority(self) -> str:
        """Return the authority component (userinfo@host:port) for this result.

        The host will be enclosed in square brackets if it contains a colon
        (indicating an IPv6 literal). The userinfo and port are included
        only when present.
        """
        return "".join(
            [
                f"{self.userinfo}@" if self.userinfo else "",
                f"[{self.host}]" if ":" in self.host else self.host,
                f":{self.port}" if self.port is not None else "",
            ]
        )

    @property
    def netloc(self) -> str:
        """Return the network location (host:port) for this result.

        The host will be enclosed in square brackets if it contains a colon
        (indicating an IPv6 literal). The port is included only when present.
        """
        return "".join(
            [
                f"[{self.host}]" if ":" in self.host else self.host,
                f":{self.port}" if self.port is not None else "",
            ]
        )

    def copy_with(self, **kwargs: typing.Optional[str]) -> "ParseResult":
        """Return a new ParseResult with specified components replaced.

        Accepts the same keyword arguments as urlparse() would accept for
        components: scheme, authority, path, query, fragment. Components not
        provided are copied from this ParseResult.
        """
        if not kwargs:
            return self

        defaults = {
            "scheme": self.scheme,
            "authority": self.authority,
            "path": self.path,
            "query": self.query,
            "fragment": self.fragment,
        }
        defaults.update(kwargs)
        return urlparse("", **defaults)

    def __str__(self) -> str:
        """Return the full URL string reconstructed from this ParseResult.

        The representation follows RFC3986 formatting rules: scheme: //authority
        path ?query #fragment. The query and fragment are included only when
        present. An empty query (i.e. present but empty) is rendered as '?'.
        """
        parts = []
        if self.scheme:
            parts.append(f"{self.scheme}:")
        if self.authority:
            parts.append(f"//{self.authority}")
        parts.append(self.path or "")
        if self.query is not None:
            parts.append(f"?{self.query}")
        if self.fragment is not None:
            parts.append(f"#{self.fragment}")
        return "".join(parts)


def _validate_component(name: str, value: str) -> None:
    if value is None:
        return
    regex = COMPONENT_REGEX.get(name)
    if regex is None:
        return
    if not regex.fullmatch(value):
        raise InvalidURL(f"Invalid {name!r}: {value!r}")


def encode_host(host: str) -> str:
    """Normalize and validate a host.

    - For IPv6 literals enclosed in brackets, validate the interior as an IPv6
      address and return the unbracketed literal.
    - For IPv4-style dotted-quad addresses, validate them and return as-is.
    - For regular hostnames, apply IDNA encoding (to ASCII) and return the
      ASCII form.

    Raises InvalidURL on invalid hosts.
    """
    if host == "":
        return host

    # IPv6 literal
    if IPv6_STYLE_HOSTNAME.fullmatch(host):
        inner = host[1:-1]
        try:
            ipaddress.IPv6Address(inner)
        except Exception:
            raise InvalidURL(f"Invalid IPv6 address: {host!r}")
        return inner

    # IPv4 style (but could be non-IP hostname)
    if IPv4_STYLE_HOSTNAME.fullmatch(host):
        try:
            ipaddress.IPv4Address(host)
        except Exception:
            raise InvalidURL(f"Invalid IPv4 address: {host!r}")
        return host

    # Otherwise treat as a hostname and IDNA-encode it.
    try:
        # idna.encode returns bytes, decode to ASCII string.
        ascii_host = idna.encode(host, uts46=True).decode("ascii")
    except idna.IDNAError as exc:
        raise InvalidURL(f"Invalid host name: {host!r}") from exc
    return ascii_host


def normalize_port(port: typing.Optional[typing.Union[int, str]]) -> typing.Optional[int]:
    """Normalize a port value to an integer or None.

    Accepts integer or string representations. Returns None for empty or
    missing ports. Raises InvalidURL for non-numeric or out-of-range ports.
    """
    if port is None or port == "":
        return None
    if isinstance(port, int):
        value = port
    else:
        # string
        if not port.isdigit():
            raise InvalidURL(f"Invalid port: {port!r}")
        try:
            value = int(port)
        except Exception:
            raise InvalidURL(f"Invalid port: {port!r}")
    if not (0 <= value <= 65535):
        raise InvalidURL(f"Port out of range: {value}")
    return value


def _parse_authority(authority: str) -> typing.Tuple[str, str, typing.Optional[int]]:
    """Parse an authority string into userinfo, host, and port."""
    if authority is None or authority == "":
        return ("", "", None)
    match = AUTHORITY_REGEX.fullmatch(authority)
    if not match:
        raise InvalidURL(f"Invalid authority: {authority!r}")
    gd = match.groupdict()
    userinfo = gd.get("userinfo") or ""
    host = gd.get("host") or ""
    port = gd.get("port")
    # Strip surrounding brackets for IPv6 literals if present in host group.
    if host.startswith("[") and host.endswith("]"):
        host_value = host
    else:
        host_value = host
    # Validate host
    encoded_host = encode_host(host_value)
    normalized_port = normalize_port(port)
    return (userinfo, encoded_host, normalized_port)


def urlparse(
    url: str,
    scheme: typing.Optional[str] = None,
    authority: typing.Optional[str] = None,
    path: typing.Optional[str] = None,
    query: typing.Optional[str] = None,
    fragment: typing.Optional[str] = None,
) -> ParseResult:
    """Parse a URL string or individual components into a ParseResult.

    If a non-empty 'url' is provided, it is parsed and validated. If 'url' is
    an empty string, individual components may be provided (scheme,
    authority, path, query, fragment) and will be validated and combined.

    The function differentiates between an absent query (query is None) and an
    empty query (query is ""), depending on the presence of the '?' in the URL
    or the explicit argument provided.

    Raises InvalidURL for invalid URLs or components.
    """
    # Validate length early
    if url is not None and len(url) > MAX_URL_LENGTH:
        raise InvalidURL("URL exceeds maximum allowed length")

    # If a full URL is provided, parse it
    if url:
        m = URL_REGEX.fullmatch(url)
        if not m:
            raise InvalidURL(f"Invalid URL: {url!r}")
        parts = m.groupdict()
        scheme_val = parts.get("scheme") or ""
        authority_val = parts.get("authority") or ""
        path_val = parts.get("path") or ""
        # Distinguish between absent and empty query: groupdict will give None if absent
        query_val = parts.get("query")
        fragment_val = parts.get("fragment")
    else:
        # Using individual components, validate them
        if scheme is not None:
            _validate_component("scheme", scheme)
            scheme_val = scheme
        else:
            scheme_val = ""
        if authority is not None:
            _validate_component("authority", authority)
            authority_val = authority
        else:
            authority_val = ""
        if path is not None:
            _validate_component("path", path)
            path_val = path
        else:
            path_val = ""
        if query is not None:
            _validate_component("query", query)
            query_val = query
        else:
            query_val = None
        if fragment is not None:
            _validate_component("fragment", fragment)
            fragment_val = fragment
        else:
            fragment_val = None

    # Normalize scheme
    scheme_val = (scheme_val or "").lower()

    # Parse authority into userinfo, host, port
    try:
        userinfo_val, host_val, port_val = _parse_authority(authority_val)
    except InvalidURL:
        # If authority parsing fails, but we have no authority, that's acceptable
        raise

    # Ensure path is present (may be empty string)
    path_val = path_val or ""

    return ParseResult(
        scheme=scheme_val,
        userinfo=userinfo_val,
        host=host_val,
        port=port_val,
        path=path_val,
        query=query_val,
        fragment=fragment_val,
    )